from math import gcd
from itertools import count, islice
def agen(): # generator of terms
    G = [0]
    for n in count(1):
        yield len(G)
        newG, maskn = [], 1<<n
        for g in G:
            i, passes = n-1, True
            while i:
                if (1<<i)&g:
                    if not (1<<gcd(i, n))&g:
                        passes = False
                        break
                i -= 1
            if passes:
                newG.append(maskn|g)
        G += newG
print(list(islice(agen(), 25))) # _Michael S. Branicky_, Apr 25 2026

